#include "kernel_operator.h"

using namespace AscendC;

class KernelCa6k02258Custom {
public:
    __aicore__ inline KernelCa6k02258Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                int32_t N, int32_t C, int32_t H_in, int32_t W_in,
                                int32_t H_out, int32_t W_out, float scaleFactor)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        N_ = N;
        C_ = C;
        H_in_ = H_in;
        W_in_ = W_in;
        H_out_ = H_out;
        W_out_ = W_out;
        scaleFactor_ = scaleFactor;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        uint32_t blockNum = GetBlockNum();
        uint32_t blockIdx = GetBlockIdx();

        for (uint32_t start = blockIdx * tileLen_; start < totalLen_;
             start += blockNum * tileLen_) {
            uint32_t end = start + tileLen_;
            if (end > totalLen_) end = totalLen_;
            for (uint32_t i = start; i < end; i++) {
                int32_t idx = static_cast<int32_t>(i);
                int32_t n = idx / (C_ * H_out_ * W_out_);
                idx %= (C_ * H_out_ * W_out_);
                int32_t c = idx / (H_out_ * W_out_);
                idx %= (H_out_ * W_out_);
                int32_t h_out = idx / W_out_;
                int32_t w_out = idx % W_out_;

                // Bilinear interpolation with PyTorch half-pixel alignment (align_corners=False)
                float h_in_f = (static_cast<float>(h_out) + 0.5f) / scaleFactor_ - 0.5f;
                float w_in_f = (static_cast<float>(w_out) + 0.5f) / scaleFactor_ - 0.5f;

                // Compute clamped integer indices
                int32_t h0 = static_cast<int32_t>(h_in_f);
                if (h_in_f < 0.0f) h0 = 0;
                if (h_in_f >= static_cast<float>(H_in_ - 1)) h0 = H_in_ - 1;
                int32_t h1 = h0 + 1;
                if (h1 >= H_in_) h1 = H_in_ - 1;

                int32_t w0 = static_cast<int32_t>(w_in_f);
                if (w_in_f < 0.0f) w0 = 0;
                if (w_in_f >= static_cast<float>(W_in_ - 1)) w0 = W_in_ - 1;
                int32_t w1 = w0 + 1;
                if (w1 >= W_in_) w1 = W_in_ - 1;

                // Clamp fractional parts
                float lx = w_in_f - static_cast<float>(w0);
                if (lx < 0.0f) lx = 0.0f;
                if (lx > 1.0f) lx = 1.0f;
                float ly = h_in_f - static_cast<float>(h0);
                if (ly < 0.0f) ly = 0.0f;
                if (ly > 1.0f) ly = 1.0f;

                // Read four corner values from input tensor (NCHW layout)
                int32_t base_idx = n * C_ * H_in_ * W_in_ + c * H_in_ * W_in_;
                float v00 = xGm_.GetValue(base_idx + h0 * W_in_ + w0);
                float v01 = xGm_.GetValue(base_idx + h0 * W_in_ + w1);
                float v10 = xGm_.GetValue(base_idx + h1 * W_in_ + w0);
                float v11 = xGm_.GetValue(base_idx + h1 * W_in_ + w1);

                // Bilinear interpolation
                float top = v00 + (v01 - v00) * lx;
                float bottom = v10 + (v11 - v10) * lx;
                float value = top + (bottom - top) * ly;

                yGm_.SetValue(i, value);
            }
        }
    }

private:
    GlobalTensor<float> xGm_;
    GlobalTensor<float> yGm_;

    uint32_t totalLen_;
    uint32_t tileLen_;
    int32_t N_, C_, H_in_, W_in_, H_out_, W_out_;
    float scaleFactor_;
};

extern "C" __global__ __aicore__ void ca6k02258_custom(GM_ADDR x, GM_ADDR y,
                                                         GM_ADDR workspace,
                                                         GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k02258Custom op;
    op.Init(x, y,
            tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.N, tiling_data.C, tiling_data.H_in, tiling_data.W_in,
            tiling_data.H_out, tiling_data.W_out, tiling_data.scaleFactor);
    op.Process();
}
